import{_ as d,C as a,o as r,c as i,a4 as t,E as n}from"./chunks/framework.CyI4nVbD.js";const m=JSON.parse('{"title":"Scalar fields, difference density, and isosurfaces","description":"","frontmatter":{},"headers":[],"relativePath":"reference/density.md","filePath":"reference/density.md"}'),s={name:"reference/density.md"};function c(l,e,p,u,f,h){const o=a("OptionsTable");return r(),i("div",null,[e[0]||(e[0]=t('<h1 id="scalar-fields-difference-density-and-isosurfaces" tabindex="-1">Scalar fields, difference density, and isosurfaces <a class="header-anchor" href="#scalar-fields-difference-density-and-isosurfaces" aria-label="Permalink to &quot;Scalar fields, difference density, and isosurfaces&quot;">​</a></h1><p>Density loading is opt-in. Standard FCF or observed-intensity/IAM maps use the green/red colours; explicitly configured or self-described custom coefficient columns are treated as deformation density and use light blue/orange. The periodic Fourier grid is retained when display or symmetry-growth settings change.</p><p>The options split into four groups by responsibility:</p><ul><li><strong><code>differenceDensity</code></strong> — source-specific calculation settings (input mode, reflection reading, IAM, corrections, FFT grids).</li><li><strong><code>scalarField</code></strong> — the shared worker policy.</li><li><strong><code>isosurface</code></strong> — 3D mesh presentation (contour level, colours, resolution, progressive steps, symmetry reuse).</li><li><strong><code>contourLines</code></strong> — planar line sections.</li></ul><p>Narrative documentation: <a href="./../general/density-concepts.html">General → Density concepts</a> and <a href="./../library/density.html">Library → Density maps</a> (which also covers custom coefficient columns and anomalous correction layouts in detail).</p>',5)),n(o,{group:"density"}),e[1]||(e[1]=t('<h2 id="common-per-source-collection-options" tabindex="-1">Common per-source collection options <a class="header-anchor" href="#common-per-source-collection-options" aria-label="Permalink to &quot;Common per-source collection options&quot;">​</a></h2><p>These accompany individual loads (<code>loadDifferenceDensity</code>, <code>loadCube</code>, <code>addScalarField</code>) and entries of <code>loadScalarFieldSources</code>; they are per-call options, not part of the defaults object above.</p><table tabindex="0"><thead><tr><th>Option</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>fieldId</code></td><td>String</td><td>Stable collection identifier. Reusing it updates the existing entry instead of appending a duplicate. Default: generated.</td></tr><tr><td><code>fieldName</code></td><td>String</td><td>Human-readable source name exposed by collection metadata and events.</td></tr><tr><td><code>activate</code></td><td>Boolean</td><td>Whether to display the entry as it loads. Default: true for individual loads; last entry for <code>loadScalarFieldSources</code>.</td></tr></tbody></table><h2 id="loadcube-options" tabindex="-1"><code>loadCube</code> options <a class="header-anchor" href="#loadcube-options" aria-label="Permalink to &quot;`loadCube` options&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>property</code></td><td>String</td><td><code>density</code>, <code>signed-density</code>, <code>orbital</code>, <code>potential</code>, or <code>generic</code>. Controls unit conversion, label, default contour, and whether one or both signs are drawn. Default: <code>&quot;density&quot;</code>.</td></tr><tr><td><code>level</code></td><td>Number</td><td>Absolute Cube contour level. Electron density defaults to 0.3 e/Å³; signed density defaults to 0.05 e/Å³; other properties default to three map standard deviations.</td></tr><tr><td><code>datasetIndex</code></td><td>Integer</td><td>Zero-based dataset/orbital selection for a multi-dataset Cube. Default: 0.</td></tr><tr><td><code>valueScale</code></td><td>Number</td><td>Explicit scalar-value multiplier. By default, Bohr-based density properties are converted from e/bohr³ to e/Å³ and other properties remain unscaled.</td></tr><tr><td><code>displayLabel</code>, <code>quantityName</code>, <code>valueUnit</code></td><td>String</td><td>Presentation metadata for generic, potential, and orbital fields. These values are emitted in density display events so the UI need not inspect the map.</td></tr><tr><td><code>periodic</code></td><td>Boolean</td><td>Controls cell wrapping. Default: true.</td></tr><tr><td><code>sign</code></td><td>String</td><td><code>positive</code>, <code>negative</code>, or <code>both</code> surface signs. Default: property-dependent.</td></tr></tbody></table>',5))])}const b=d(s,[["render",c]]);export{m as __pageData,b as default};
